class Solution {
    /**
     * Returns the smallest index i such that s[i] == s[n - i - 1].
     * If no such index exists, returns -1.
     *
     * @param s The input string.
     * @return The smallest index i satisfying the condition, or -1.
     */
    public static long solve(String s) {
        int n = s.length();

        // We need to check indices i starting from 0 up to the middle of the string.
        // The condition is s[i] == s[n - i - 1].
        // We are looking for the *smallest* such i.

        for (int i = 0; i < n; i++) {
            int j = n - 1 - i;

            if (s.charAt(i) == s.charAt(j)) {
                // Since we iterate i from 0 upwards, the first one we find is the smallest.
                // Note: If i == j (i.e., n is odd and i is the middle index), the condition s[i] == s[i] is always true.
                // The problem implies we should return this index if it's the smallest.
                // Example 2: s = "abc", n=3.
                // i=0: s[0]='a', s[2]='c'. Not equal.
                // i=1: s[1]='b', s[1]='b'. Equal. Return 1.
                // i=2: s[2]='c', s[0]='a'. Not equal.

                // The requirement is to return the *minimal* index i.
                // If i reaches the point where i > n - i - 1 (i.e., 2i > n-1 or i > (n-1)/2), 
                // we are re-checking pairs already checked, or we are at the middle element.

                // Since we are looking for the smallest i, we can stop once i passes the halfway point, 
                // but since the condition might be true for i > n/2 as well (though usually redundant if we check only up to n/2),
                // iterating up to n-1 is safe, as the first match will be the smallest.

                // Let's verify the constraints on i. If i > n-i-1, then i > (n-1)/2. 
                // For i = floor(n/2) + 1, j = n - i - 1 < i. This pair (i, j) is the same as (j, i) checked earlier.
                // Since we want the *smallest* i, we only need to check up to i <= n - i - 1, or 2i <= n-1, so i <= (n-1)/2.

                // Let's stick to the full loop for simplicity and correctness based on finding the *minimal* i.
                // The loop structure naturally finds the minimal i.
                return (long) i;
            }
        }

        // If the loop finishes without returning, no such index exists.
        return -1L;
    }
